import React, { useEffect } from "react";
import { useForm, Controller } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { useNavigate } from "react-router-dom";
import { Button } from "../../components/common/Button";
import { Input } from "../../components/common/Input";
import { getRoles } from "../../services/role.service";
import { Eye, EyeOff, Users } from "lucide-react";
import FormLayout from "../../components/common/FormLayout";
import DropdownSearch from "../../components/common/DropdownSearch";
import ToggleSwitch from "../../components/common/ToggleSwitch";
import {
  getDistricts,
  getSchemesWithTypes,
  getSchemeTypes,
} from "../../services/master.service";
import { getEmployeesByDistrictAndScheme } from "../../services/workforce.service";

// Base schema with common fields
const baseSchema = z.object({
  full_name: z.string().min(2, "Name must be at least 2 characters"),
  username: z.string().min(3, "Username must be at least 3 characters"),
  email: z.string().email("Invalid email address"),
  mobile_no: z
    .string()
    .optional()
    .or(z.literal(""))
    .refine((val) => {
      if (val === undefined || val === "") return true;
      return /^\d{10}$/.test(val);
    }, "Mobile number must be exactly 10 digits"),
  role_id: z.coerce.number().min(1, "Please select a valid role"),
  is_active: z.boolean().optional(),
  scheme_id: z.number().nullable().optional(),
  district_id: z.number().nullable().optional(),
  linked_employee_id: z.number().nullable().optional(),
  // Batch assignment fields for merit list review
  review_batch_start: z.number().nullable().optional(),
  review_batch_end: z.number().nullable().optional(),
});

// Schema for adding a new user (password required unless linked to employee)
const addUserSchema = baseSchema.extend({
  password: z.string().optional(),
});

// Schema for editing a user (password optional)
const editUserSchema = baseSchema.extend({
  password: z.string().optional().or(z.literal("")),
});

export const UserForm = ({
  initialData,
  isViewMode = false,
  onSubmit,
  isLoading,
  title,
}) => {
  const navigate = useNavigate();
  const [roles, setRoles] = React.useState([]);

  const [showPassword, setShowPassword] = React.useState(false);
  const isEditMode = !!initialData;
  const [schemeOptions, setSchemeOptions] = React.useState([]);
  const [schemeTypes, setSchemeTypes] = React.useState([]);
  const [districtOptions, setDistrictOptions] = React.useState([]);
  const [employeeOptions, setEmployeeOptions] = React.useState([]);

  const {
    register,
    handleSubmit,
    formState: { errors },
    reset,
    control,
    watch,
    setValue,
  } = useForm({
    resolver: zodResolver(isEditMode ? editUserSchema : addUserSchema),
    defaultValues: {
      full_name: "",
      username: "",
      email: "",
      mobile_no: "",
      password: "",
      scheme_id: undefined,
      district_id: undefined,
      linked_employee_id: undefined,
      role_id:
        initialData?.role_id != null
          ? Number(initialData.role_id)
          : initialData?.role?.role_id != null
            ? Number(initialData.role.role_id)
            : undefined,
      is_active: true,
      review_batch_start: null,
      review_batch_end: null,
      ...initialData,
    },
  });

  useEffect(() => {
    const loadRoles = async () => {
      const data = await getRoles();
      // Handle both array [] and object { roles: [] } response types from API
      const rolesList = Array.isArray(data) ? data : data.roles || [];
      setRoles(rolesList);
    };
    loadRoles();
  }, []);

  useEffect(() => {
    const loadDropdowns = async () => {
      try {
        const [d, s, st] = await Promise.all([
          getDistricts(),
          getSchemesWithTypes(),
          getSchemeTypes(),
        ]);

        setSchemeOptions(
          (s || []).map((item) => ({
            id: item.scheme_id,
            name: item.scheme_name,
            scheme_type_id: item.scheme_type_id,
            district_id: item.district_id,
          })),
        );
        setSchemeTypes(st || []);
        setDistrictOptions(
          (d || []).map((item) => ({
            id: item.district_id,
            name: item.district_name,
          })),
        );
      } catch (err) {
        console.error("Dropdown error", err);
      }
    };

    loadDropdowns();
  }, []);

  useEffect(() => {
    if (initialData) {
      // Ensure password is reset to empty string on edit load so validation works
      // Also ensure role_id is correctly set if it comes as a nested object or string
      const formData = {
        ...initialData,
        role_id:
          initialData.role_id != null
            ? Number(initialData.role_id)
            : initialData.role?.role_id != null
              ? Number(initialData.role.role_id)
              : undefined,
        password: "",
      };
      if (formData.role_id !== undefined && formData.role_id !== null) {
        formData.role_id = Number(formData.role_id);
      }
      reset(formData);
    }
  }, [initialData, reset]);

  // Debug role binding
  const currentRoleId = watch("role_id");
  const selectedDistrictId = watch("district_id");
  const selectedSchemeId = watch("scheme_id");
  const selectedEmployeeId = watch("linked_employee_id");

  // Filter schemes by selected district, then group by type
  const filteredSchemes = selectedDistrictId
    ? schemeOptions.filter(s => s.district_id === selectedDistrictId)
    : schemeOptions;

  const schemesByType = schemeTypes.reduce((acc, type) => {
    const schemes = filteredSchemes.filter(scheme => scheme.scheme_type_id === type.scheme_type_id);
    if (schemes.length > 0) {
      acc[type.scheme_type_id] = { ...type, schemes };
    }
    return acc;
  }, {});
  
  useEffect(() => {
    if (isEditMode) {
      console.debug("UserForm role debug", {
        initialRoleId: initialData?.role_id || initialData?.role?.role_id,
        currentRoleId,
        rolesLoaded: roles.length,
      });
    }
  }, [currentRoleId, initialData, isEditMode, roles.length]);
  
  // Load employees when district and scheme are selected
  useEffect(() => {
    const loadEmployees = async () => {
      if (selectedDistrictId && selectedSchemeId) {
        try {
          const employees = await getEmployeesByDistrictAndScheme(selectedDistrictId, selectedSchemeId);
          setEmployeeOptions(employees);
        } catch (error) {
          console.error('Error loading employees:', error);
          setEmployeeOptions([]);
        }
      } else {
        setEmployeeOptions([]);
      }
    };
    
    loadEmployees();
  }, [selectedDistrictId, selectedSchemeId]);

  // Load employees on edit when district and scheme are already set
  useEffect(() => {
    if (isEditMode && selectedDistrictId && selectedSchemeId) {
      const loadEmployees = async () => {
        try {
          const employees = await getEmployeesByDistrictAndScheme(selectedDistrictId, selectedSchemeId);
          setEmployeeOptions(employees);
        } catch (error) {
          console.error('Error loading employees:', error);
          setEmployeeOptions([]);
        }
      };
      
      loadEmployees();
    }
  }, [isEditMode, selectedDistrictId, selectedSchemeId]);
  
  // Auto-fill form fields when employee is selected
  useEffect(() => {
    if (selectedEmployeeId && employeeOptions.length > 0) {
      const selectedEmployee = employeeOptions.find(emp => emp.employee_id === selectedEmployeeId);
      if (selectedEmployee) {
        setValue('username', selectedEmployee.email);
        setValue('email', selectedEmployee.email);
        setValue('full_name', selectedEmployee.full_name);
      }
    }
  }, [selectedEmployeeId, employeeOptions, setValue]);

  const handleFormSubmit = (data) => {
    // Client-side validation: password required when no employee is linked (add mode only)
    if (!isEditMode && !data.linked_employee_id && (!data.password || data.password.length < 6)) {
      // This will be caught by Zod validation, but we add client-side check too
      return;
    }

    // If in edit mode and password is empty, remove it from the payload
    if (isEditMode && !data.password) {
      const { password, ...rest } = data;
      onSubmit(rest);
    } else {
      onSubmit(data);
    }
  };

  return (
    <FormLayout
      title="User"
      icon={Users}
      onSubmit={handleSubmit(handleFormSubmit)}
      onCancel={() => navigate("/users")}
      isEditMode={isEditMode}
      isViewMode={isViewMode}
      loading={isLoading}
    >
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        <Input
          label="Full Name"
          placeholder="John Doe"
          error={errors.full_name?.message}
          disabled={isViewMode}
          {...register("full_name")}
        />

        <Input
          label="Username"
          placeholder="johndoe"
          error={errors.username?.message}
          disabled={isViewMode}
          {...register("username")}
        />

        <Input
          label="Email Address"
          placeholder="john@example.com"
          type="email"
          error={errors.email?.message}
          disabled={isViewMode}
          {...register("email")}
        />

        <Input
          label={
            isEditMode 
              ? "Password (leave blank to keep)" 
              : selectedEmployeeId 
                ? "Password (will use employee's password)" 
                : "Password"
          }
          placeholder={
            isEditMode 
              ? "********" 
              : selectedEmployeeId 
                ? "Employee password will be used" 
                : "Enter password"
          }
          type={showPassword ? "text" : "password"}
          endIcon={
            !isViewMode &&
            (showPassword ? (
              <EyeOff className="h-4 w-4" />
            ) : (
              <Eye className="h-4 w-4" />
            ))
          }
          onEndIconClick={() => !isViewMode && setShowPassword(!showPassword)}
          error={errors.password?.message}
          disabled={isViewMode}
          {...register("password")}
        />

        <Input
          label="Mobile Number"
          placeholder="9876543210"
          error={errors.mobile_no?.message}
          disabled={isViewMode}
          inputMode="numeric"
          maxLength={10}
          onInput={(e) => {
            e.target.value = e.target.value.replace(/\D/g, "").slice(0, 10);
          }}
          {...register("mobile_no")}
        />

        <div className="space-y-1.5">
          <label className="block text-sm font-semibold text-slate-700">
            Role
          </label>
          <Controller
            name="role_id"
            control={control}
            render={({ field: { value, onChange } }) => (
              <DropdownSearch
                value={value}
                onChange={(e) => onChange(Number(e.target.value))}
                options={roles.map((r) => ({
                  id: r.role_id,
                  name: r.role_name,
                }))}
                placeholder="Select Role"
                disabled={isViewMode}
              />
            )}
          />
          {errors.role_id && (
            <p className="mt-1 text-sm text-red-500">
              {errors.role_id.message}
            </p>
          )}
        </div>

        <div className="space-y-1.5">
          <label className="block text-sm font-semibold text-slate-700">
            District
          </label>
          <Controller
            name="district_id"
            control={control}
            render={({ field: { value, onChange } }) => (
              <DropdownSearch
                value={value}
                onChange={(e) => {
                  const val = e.target.value;
                  onChange(val ? Number(val) : null);
                  setValue('scheme_id', null); // Reset scheme selection
                  setValue('linked_employee_id', null); // Reset employee selection
                }}
                options={districtOptions}
                placeholder="Select District"
                disabled={isViewMode}
              />
            )}
          />
        </div>

        <div className="space-y-1.5">
          <label className="block text-sm font-semibold text-slate-700">
            Scheme
          </label>
          <Controller
            name="scheme_id"
            control={control}
            render={({ field: { value, onChange } }) => (
              <DropdownSearch
                value={value}
                onChange={(e) => {
                  const val = e.target.value;
                  onChange(val ? Number(val) : null);
                  setValue('linked_employee_id', null); // Reset employee selection
                }}
                options={Object.values(schemesByType).flatMap(type => 
                type.schemes.map(scheme => ({
                  id: scheme.id,
                  name: `${scheme.name} (${type.scheme_name})`,
                  group: type.scheme_name
                }))
              )}
                placeholder={!selectedDistrictId ? "First select District" : filteredSchemes.length === 0 ? "No schemes in this district" : "Select Scheme"}
                disabled={isViewMode || !selectedDistrictId}
              />
            )}
          />
          {errors.scheme_id && (
            <p className="text-sm text-red-500">
              {errors.scheme_id.message}
            </p>
          )}
        </div>

        {/* Employee Linking */}
        <div className="space-y-1.5">
          <label className="block text-sm font-semibold text-slate-700">
            Link to Employee <span className="text-slate-400 font-normal">(Optional)</span>
          </label>
          <Controller
            name="linked_employee_id"
            control={control}
            render={({ field: { value, onChange } }) => (
              <DropdownSearch
                value={value}
                onChange={(e) => {
                  const val = e.target.value;
                  onChange(val ? Number(val) : null);
                }}
                options={employeeOptions.map(emp => ({
                  id: emp.employee_id,
                  name: `${emp.full_name || 'Unknown'} (${emp.employee_code})`,
                }))}
                placeholder={!selectedDistrictId ? "First select District" : !selectedSchemeId ? "Then select Scheme" : employeeOptions.length === 0 ? "No employees found" : "Select Employee"}
                disabled={isViewMode || !selectedDistrictId || !selectedSchemeId}
              />
            )}
          />
        </div>
      </div>

      {/* Batch Assignment Section */}
      <div className="border-t border-slate-200 pt-6 mt-6">
        <h3 className="text-lg font-semibold text-slate-900 mb-4">Merit List Review Assignment</h3>
        <p className="text-sm text-slate-600 mb-4">
          Assign global rank ranges for merit list review. This applies to ALL posts automatically.
        </p>
        
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <Input
            label="Batch Start Rank"
            placeholder="1"
            type="number"
            min="1"
            error={errors.review_batch_start?.message}
            disabled={isViewMode}
            {...register("review_batch_start", { valueAsNumber: true })}
          />

          <Input
            label="Batch End Rank"
            placeholder="50"
            type="number"
            min="1"
            error={errors.review_batch_end?.message}
            disabled={isViewMode}
            {...register("review_batch_end", { valueAsNumber: true })}
          />
        </div>

        <div className="mt-3 p-3 bg-blue-50 border border-blue-200 rounded-lg">
          <p className="text-sm text-blue-700">
            <strong>Example:</strong> Start=1, End=50 means this reviewer sees first 50 applicants of ANY post.
            Leave blank to see all applications.
          </p>
        </div>
      </div>

      {/* Active Status */}
      <Controller
        name="is_active"
        control={control}
        render={({ field: { value, onChange } }) => (
          <ToggleSwitch
            label="Active Status"
            description={
              value ? "User is currently active" : "User is currently inactive"
            }
            checked={!!value}
            onChange={onChange}
            disabled={isViewMode}
          />
        )}
      />
    </FormLayout>
  );
};
